BEGIN; CREATE TABLE IF NOT EXISTS public.returned_goods_records (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), tx_date date NOT NULL, product_id uuid NOT NULL REFERENCES public.products(id), customer_id uuid NULL REFERENCES public.customers(id), product_name_snapshot text NOT NULL, product_spec_snapshot text NULL, tx_type text NOT NULL DEFAULT 'in' CHECK (tx_type IN ('in','adjust_in','adjust_out')), qty numeric NOT NULL CHECK (qty > 0), unit_cost numeric NULL, note text NULL, adjusted_from_transaction_id uuid NULL REFERENCES public.returned_goods_records(id), created_at timestamptz NOT NULL DEFAULT now(), created_by uuid NULL REFERENCES auth.users(id), updated_at timestamptz NOT NULL DEFAULT now(), updated_by uuid NULL REFERENCES auth.users(id), deleted_at timestamptz NULL, deleted_by uuid NULL REFERENCES auth.users(id)); COMMENT ON TABLE public.returned_goods_records IS 'Hang tra ve - bang theo doi rieng, khong ghi vao ton kho va khong tinh gia tri'; CREATE INDEX IF NOT EXISTS idx_returned_goods_product_id ON public.returned_goods_records(product_id); CREATE INDEX IF NOT EXISTS idx_returned_goods_customer_id ON public.returned_goods_records(customer_id); CREATE INDEX IF NOT EXISTS idx_returned_goods_tx_date ON public.returned_goods_records(tx_date); CREATE INDEX IF NOT EXISTS idx_returned_goods_not_deleted ON public.returned_goods_records(tx_date) WHERE deleted_at IS NULL; CREATE OR REPLACE FUNCTION public.returned_goods_touch_row() RETURNS trigger LANGUAGE plpgsql SET search_path = public AS $$ BEGIN IF TG_OP = 'INSERT' THEN NEW.created_at := COALESCE(NEW.created_at, now()); NEW.created_by := COALESCE(NEW.created_by, auth.uid()); END IF; NEW.updated_at := now(); NEW.updated_by := auth.uid(); RETURN NEW; END; $$; CREATE OR REPLACE FUNCTION public.returned_goods_block_hard_delete() RETURNS trigger LANGUAGE plpgsql SET search_path = public AS $$ BEGIN RAISE EXCEPTION 'Bi chan de bao ve du lieu hang tra ve: khong duoc xoa cung, hay danh dau xoa mem.'; END; $$; DROP TRIGGER IF EXISTS trg_returned_goods_touch ON public.returned_goods_records; CREATE TRIGGER trg_returned_goods_touch BEFORE INSERT OR UPDATE ON public.returned_goods_records FOR EACH ROW EXECUTE FUNCTION public.returned_goods_touch_row(); DROP TRIGGER IF EXISTS trg_returned_goods_block_delete ON public.returned_goods_records; CREATE TRIGGER trg_returned_goods_block_delete BEFORE DELETE ON public.returned_goods_records FOR EACH ROW EXECUTE FUNCTION public.returned_goods_block_hard_delete(); ALTER TABLE public.returned_goods_records ENABLE ROW LEVEL SECURITY; DROP POLICY IF EXISTS "returned_goods_select_standard" ON public.returned_goods_records; CREATE POLICY "returned_goods_select_standard" ON public.returned_goods_records FOR SELECT TO authenticated USING (deleted_at IS NULL); DROP POLICY IF EXISTS "returned_goods_select_privileged" ON public.returned_goods_records; CREATE POLICY "returned_goods_select_privileged" ON public.returned_goods_records FOR SELECT TO authenticated USING (public.is_admin() OR public.is_manager()); DROP POLICY IF EXISTS "returned_goods_insert_privileged" ON public.returned_goods_records; CREATE POLICY "returned_goods_insert_privileged" ON public.returned_goods_records FOR INSERT TO authenticated WITH CHECK (public.is_admin() OR public.is_manager()); DROP POLICY IF EXISTS "returned_goods_update_privileged" ON public.returned_goods_records; CREATE POLICY "returned_goods_update_privileged" ON public.returned_goods_records FOR UPDATE TO authenticated USING (public.is_admin() OR public.is_manager()) WITH CHECK (public.is_admin() OR public.is_manager()); DROP POLICY IF EXISTS "returned_goods_delete_privileged" ON public.returned_goods_records; CREATE POLICY "returned_goods_delete_privileged" ON public.returned_goods_records FOR DELETE TO authenticated USING (public.is_admin()); GRANT SELECT, INSERT, UPDATE ON public.returned_goods_records TO authenticated; NOTIFY pgrst, 'reload schema'; COMMIT;
